"""Unit tests for HR6 (RLS role contract binds to a real dim column)."""

from __future__ import annotations

from pathlib import Path

import pytest

from seshat.core import RuleContext, Severity
from seshat.rules.rls_access import check_rls_role_bindings

pytestmark = pytest.mark.unit

_REPO = Path(__file__).resolve().parents[2]

_FIXTURE_GOLD_SQL = (
    "CREATE SCHEMA IF NOT EXISTS gold;\n"
    "CREATE TABLE gold.dim_store (\n"
    "  store_sk INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n"
    "  store_id TEXT,\n"
    "  region TEXT,\n"
    "  CONSTRAINT store_uq UNIQUE (store_id)\n"
    ");\n"
    "CREATE TABLE gold.fct_sales (\n"
    "  sale_sk INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n"
    "  store_sk INT,\n"
    "  amount NUMERIC(10,2)\n"
    ");\n"
)


def _mig(tmp_path: Path, name: str, sql: str) -> str:
    rel = f"warehouse/migrations/{name}"
    dest = tmp_path / rel
    dest.parent.mkdir(parents=True, exist_ok=True)
    dest.write_text(sql, encoding="utf-8")
    return rel


def _role(tmp_path: Path, table: str, name: str, yaml_text: str) -> str:
    rel = f"mappings/{table}/roles/{name}.yaml"
    dest = tmp_path / rel
    dest.parent.mkdir(parents=True, exist_ok=True)
    dest.write_text(yaml_text, encoding="utf-8")
    return rel


def _ctx(tmp_path: Path, *rel: str) -> RuleContext:
    return RuleContext(repo_root=tmp_path, tracked_files=tuple(rel))


def _with_fixture_gold(tmp_path: Path) -> str:
    return _mig(tmp_path, "0001_gold.sql", _FIXTURE_GOLD_SQL)


_CLEAN_CONTRACT = (
    "name: RegionManager\n"
    "filter:\n"
    "  gold_table: gold.dim_store\n"
    "  column: region\n"
    "readiness:\n"
    "  status: pass\n"
    '  evidence: ["approved by owner on 2026-07-04"]\n'
    "  blocking_reasons: []\n"
)


# --- zero-contract case (Q-ZERO-ROLES, FR-010): absence emits nothing ---


def test_zero_contracts_emits_no_findings(tmp_path: Path) -> None:
    mig = _with_fixture_gold(tmp_path)
    ctx = _ctx(tmp_path, mig)
    assert list(check_rls_role_bindings(ctx)) == []


def test_passes_against_real_committed_tree() -> None:
    """The real repo tree has no committed rls-role-contract.yaml yet; HR6
    must emit zero findings against it (mirrors HR7's SC-001-style test)."""
    ctx = RuleContext(repo_root=_REPO, tracked_files=())
    assert list(check_rls_role_bindings(ctx)) == []


# --- US2: a well-formed role contract binds cleanly and clears HR6 ---


def test_well_formed_binding_produces_no_finding(tmp_path: Path) -> None:
    mig = _with_fixture_gold(tmp_path)
    role = _role(tmp_path, "sales", "RegionManager", _CLEAN_CONTRACT)
    ctx = _ctx(tmp_path, mig, role)
    assert list(check_rls_role_bindings(ctx)) == []


# --- US1: a declared role with no real filter binding fails the gate ---


def test_blank_filter_column_fails(tmp_path: Path) -> None:
    mig = _with_fixture_gold(tmp_path)
    contract = (
        "name: RegionManager\n"
        "filter:\n"
        "  gold_table: gold.dim_store\n"
        '  column: ""\n'
        "readiness:\n"
        "  status: not_started\n"
        "  evidence: []\n"
        "  blocking_reasons: []\n"
    )
    role = _role(tmp_path, "sales", "RegionManager", contract)
    ctx = _ctx(tmp_path, mig, role)
    findings = list(check_rls_role_bindings(ctx))
    assert len(findings) == 1
    assert findings[0].rule_id == "HR6"
    assert findings[0].severity is Severity.ERROR
    assert "RegionManager" in findings[0].message
    assert "filter.column" in findings[0].message


