def test_fact_table_binding_hard_fails(tmp_path: Path) -> None:
    """Clarification C1: a gold.fct_* binding is Severity.ERROR, never
    Severity.WARNING -- a fact-bound role is the exact leak-through
    direction this feature exists to close."""
    mig = _with_fixture_gold(tmp_path)
    contract = (
        "name: RegionManager\n"
        "filter:\n"
        "  gold_table: gold.fct_sales\n"
        "  column: store_sk\n"
        "readiness:\n"
        "  status: not_started\n"
        "  evidence: []\n"
        "  blocking_reasons: []\n"
    )
    role = _role(tmp_path, "sales", "RegionManager", contract)
    ctx = _ctx(tmp_path, mig, role)
    findings = list(check_rls_role_bindings(ctx))
    assert len(findings) == 1
    assert findings[0].severity is Severity.ERROR
    assert "dim" in findings[0].message.lower()
    assert "fact" in findings[0].message.lower()


