def test_duplicate_role_name_fails(tmp_path: Path) -> None:
    mig = _with_fixture_gold(tmp_path)
    contract_a = (
        "name: RegionManager\n"
        "filter:\n"
        "  gold_table: gold.dim_store\n"
        "  column: region\n"
        "readiness:\n"
        "  status: not_started\n"
        "  evidence: []\n"
        "  blocking_reasons: []\n"
    )
    contract_b = (
        "name: RegionManager\n"
        "filter:\n"
        "  gold_table: gold.dim_store\n"
        "  column: store_id\n"
        "readiness:\n"
        "  status: not_started\n"
        "  evidence: []\n"
        "  blocking_reasons: []\n"
    )
    role_a = _role(tmp_path, "sales", "RegionManagerA", contract_a)
    role_b = _role(tmp_path, "sales", "RegionManagerB", contract_b)
    ctx = _ctx(tmp_path, mig, role_a, role_b)
    findings = list(check_rls_role_bindings(ctx))
    assert len(findings) == 2
    assert all(f.severity is Severity.ERROR for f in findings)
    assert all("RegionManager" in f.message for f in findings)
    locators = {f.locator for f in findings}
    assert locators == {role_a, role_b}


def test_not_started_and_blocked_are_not_treated_as_findings_on_their_own(
    tmp_path: Path,
) -> None:
    """A well-formed binding with status not_started (or blocked, with its
    own recorded blocking_reasons) is a lifecycle state HR6 must not
    re-decide or launder into an extra finding -- it only checks structure
    (Principle VIII), never the lifecycle status itself except the
    pass-with-no-evidence defect (FR-008)."""
    mig = _with_fixture_gold(tmp_path)
    not_started = (
        "name: RegionManager\n"
        "filter:\n"
        "  gold_table: gold.dim_store\n"
        "  column: region\n"
        "readiness:\n"
        "  status: not_started\n"
        "  evidence: []\n"
        "  blocking_reasons: []\n"
    )
    role = _role(tmp_path, "sales", "RegionManager", not_started)
    ctx = _ctx(tmp_path, mig, role)
    assert list(check_rls_role_bindings(ctx)) == []

    blocked = (
        "name: OtherManager\n"
        "filter:\n"
        "  gold_table: gold.dim_store\n"
        "  column: region\n"
        "readiness:\n"
        "  status: blocked\n"
        "  evidence: []\n"
        '  blocking_reasons: ["pending owner review"]\n'
    )
    role2 = _role(tmp_path, "other", "OtherManager", blocked)
    ctx2 = _ctx(tmp_path, mig, role, role2)
    assert list(check_rls_role_bindings(ctx2)) == []


# --- static-only, no live-proof claim, no numeric score ---


def test_module_imports_no_database_driver() -> None:
    src = (_REPO / "src" / "seshat" / "rules" / "rls_access.py").read_text(
        encoding="utf-8"
    )
    for forbidden in ("import psycopg", "import sqlalchemy", ".connect(", "DSN"):
        assert forbidden not in src


def test_findings_never_carry_a_numeric_score(tmp_path: Path) -> None:
    mig = _with_fixture_gold(tmp_path)
    not_started_tail = (
        "readiness:\n  status: not_started\n  evidence: []\n  blocking_reasons: []\n"
    )
    defects = [
        (
            'name: A\nfilter:\n  gold_table: gold.dim_store\n  column: ""\n'
            + not_started_tail
        ),
        (
            "name: B\nfilter:\n  gold_table: gold.dim_store\n  column: nope\n"
            + not_started_tail
        ),
        (
            "name: C\nfilter:\n  gold_table: gold.fct_sales\n  column: store_sk\n"
            + not_started_tail
        ),
        (
            "name: D\nfilter:\n  gold_table: gold.dim_store\n  column: region\n"
            "readiness:\n  status: pass\n  evidence: []\n  blocking_reasons: []\n"
        ),
    ]
    rels = [mig]
    for i, text in enumerate(defects):
        rels.append(_role(tmp_path, f"t{i}", f"Role{i}", text))
    ctx = _ctx(tmp_path, *rels)
    findings = list(check_rls_role_bindings(ctx))
    assert findings  # sanity: defects actually triggered
    for f in findings:
        assert "%" not in f.message
        assert not re_has_bare_number_confidence(f.message)


def re_has_bare_number_confidence(message: str) -> bool:
    import re

    return re.search(r"\b\d+\s*(?:/|of)\s*\d+\b", message) is not None


def test_no_c086_specific_token_in_rule_source() -> None:
    src = (_REPO / "src" / "seshat" / "rules" / "rls_access.py").read_text(
        encoding="utf-8"
    )
    for token in ("retail_store_sales", "_rss", "dim_location_rss", "dim_customer_rss"):
        assert token not in src
